digraph G {
    rankdir=LR;
    node [shape=box, style=filled, fillcolor=lightgrey];
    edge [arrowhead=normal];

    subgraph cluster_CPU {
        label="Central Processing Unit (CPU)";
        style=filled;
        fillcolor=lightblue;

        subgraph cluster_Control {
            label="Control Circuits";
            style=filled;
            fillcolor=white;
            IR [label="Instruction Register (IR)"];
            PC [label="Program Counter (PC)"];
        }

        subgraph cluster_Registers {
            label="Registers";
            style=filled;
            fillcolor=white;
            AC [label="Accumulator (AC)"];
            MQ [label="Multiplier-Quotient (MQ)"];
            MBR [label="Memory Buffer Register (MBR)"];
            IBR [label="Instruction Buffer Register (IBR)"];
            MAR [label="Memory Address Register (MAR)"];
        }
    }

    MainMemory [label="Main Memory", shape=cylinder, fillcolor=lightgreen];
    InputEquipment [label="Input Equipment", shape=ellipse, fillcolor=yellow];
    OutputEquipment [label="Output Equipment", shape=ellipse, fillcolor=yellow];

    // Connections within CPU
    ControlCircuits -> IR [label="decodes"];
    IR -> ControlCircuits [label="executes"];
    PC -> ControlCircuits [label="points to next instruction"];
    ControlCircuits -> PC [label="updates"];

    // Connections between CPU and Main Memory
    MAR -> MainMemory [label="address"];
    MainMemory -> MBR [label="data"];
    MBR -> MainMemory [label="data"];

    // Connections for registers
    MBR -> AC [label="loads data"];
    AC -> MBR [label="stores data"];
    MBR -> MQ [label="loads data"];
    MQ -> MBR [label="stores data"];
    IBR -> ControlCircuits [label="holds instruction"];

    // Connections with Input/Output
    InputEquipment -> MBR [label="inputs data"];
    MBR -> OutputEquipment [label="outputs data"];
}

