    ALU -> MQ [dir=forward];
    MAR [label="Memory Address Register (MAR)"];
    MBR [label="Memory Buffer Register (MBR)"];
    CU -> MAR [style=dashed];
    CU -> MBR [style=dashed];
    CU -> ALU [style=dashed];
    CU -> PC [style=dashed];
    CU -> I_O [style=dashed];
    PC -> MAR [label="address"];
    IR -> CU [label="opcode"];
    IR -> MAR [label="address field"];
    MBR -> IR [label="instruction fetch"];
    ALU -> MBR [dir=both];
