digraph G {
    rankdir=LR;
    node [shape=box, style=filled, fillcolor=lightgray];
    edge [arrowhead=normal];

    subgraph cluster_cpu {
        label="CPU";
        style=filled;
        fillcolor=lightblue;

        CU [label="Control Unit"];
        ALU [label="ALU"];
        Reg [label="Registers"];
        PC [label="Program Counter (PC)"];

        CU -> ALU [style=invis];
        ALU -> Reg [style=invis];
        Reg -> PC [style=invis];
    }

    subgraph cluster_instruction {
        label="Instruction Memory (ROM/RAM)";
        style=filled;
        fillcolor=lightyellow;

        IM [label="Instruction Memory", shape=box];
    }

    subgraph cluster_data {
        label="Data Memory (RAM)";
        style=filled;
        fillcolor=lightyellow;

        DM [label="Data Memory", shape=box];
    }

    // Instruction Bus connections
    PC -> IM [label="Address Lines", dir=forward];
    IM -> CU [label="Data Lines", dir=forward];
    CU -> IM [label="Control Lines (e.g., MemRead)", dir=forward];

    // Data Bus connections
    ALU -> DM [label="Address Lines", dir=forward];
    DM -> Reg [label="Data Lines", dir=forward];
    Reg -> DM [label="Data Lines", dir=forward];
    CU -> DM [label="Control Lines (e.g., MemRead, MemWrite)", dir=forward];

    // Layout hints
    { rank=same; IM; CU; DM; }
}
